import { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../api/client';

const T = {
  bg: '#07070f', bg1: '#0d0d1c', bg2: '#12122a', bg3: '#1a1a35',
  border: '#ffffff0f', border2: '#ffffff1a',
  text: '#f0f0f5', text2: '#9090a8', text3: '#5a5a72',
  purple: '#7c6fef', purpleD: '#5a4fd4', purpleL: '#a99ef7',
  green: '#22c98e', amber: '#f59e0b', red: '#f06060', blue: '#4a9ef0',
};

// ── HELPERS ──────────────────────────────────────────────────────────────────
function Av({ name = '?', color = T.purple, size = 34 }) {
  const initials = name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
  return (
    <div style={{ width: size, height: size, borderRadius: '50%', background: color + '33', border: `1.5px solid ${color}55`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: size * 0.33, fontWeight: 700, color, flexShrink: 0 }}>
      {initials}
    </div>
  );
}

function Bar({ val, color = T.purple, h = 4 }) {
  return (
    <div style={{ height: h, background: T.bg3, borderRadius: 99, overflow: 'hidden' }}>
      <div style={{ height: '100%', width: `${Math.min(100, val || 0)}%`, background: color, borderRadius: 99, transition: 'width 0.5s ease' }} />
    </div>
  );
}

function Badge({ label, color = T.purple }) {
  return <span style={{ background: color + '22', color, border: `1px solid ${color}44`, borderRadius: 6, padding: '2px 8px', fontSize: 11, fontWeight: 600 }}>{label}</span>;
}

function Stat({ label, value, color = T.text }) {
  return (
    <div style={{ background: T.bg2, border: `1px solid ${T.border}`, borderRadius: 12, padding: '14px 18px' }}>
      <div style={{ color: T.text3, fontSize: 12, marginBottom: 6 }}>{label}</div>
      <div style={{ color, fontSize: 22, fontWeight: 700 }}>{value}</div>
    </div>
  );
}

function TypeTag({ type }) {
  const map = { video: [T.purple, '▶ Video'], quiz: [T.green, '✦ Quiz'], assignment: [T.amber, '↑ Assignment'], reading: [T.blue, '◎ Reading'] };
  const [col, label] = map[type] || [T.text3, type];
  return <span style={{ color: col, fontSize: 11, fontWeight: 600, background: col + '18', padding: '2px 7px', borderRadius: 5 }}>{label}</span>;
}

// ── VIDEO MODAL ──────────────────────────────────────────────────────────────
function VideoModal({ lesson, onClose, onComplete }) {
  const [playing, setPlaying] = useState(false);
  const [prog, setProg] = useState(0);
  const [sec, setSec] = useState(0);
  const iv = useRef(null);

  const toggle = () => {
    if (playing) { clearInterval(iv.current); setPlaying(false); }
    else {
      setPlaying(true);
      iv.current = setInterval(() => {
        setProg(p => {
          if (p >= 100) { clearInterval(iv.current); setPlaying(false); onComplete(); return 100; }
          return p + 0.3;
        });
        setSec(s => s + 1);
      }, 300);
    }
  };
  useEffect(() => () => clearInterval(iv.current), []);
  const fmt = s => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;

  return (
    <Modal onClose={onClose}>
      <div style={{ background: '#0a0a16', aspectRatio: '16/9', display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 12 }}>
        <div style={{ fontSize: 52, opacity: 0.4 }}>🎬</div>
        <div style={{ color: T.text2, fontSize: 14 }}>{lesson.title}</div>
      </div>
      <div style={{ padding: '16px 22px' }}>
        <div style={{ height: 4, background: T.bg3, borderRadius: 99, cursor: 'pointer', marginBottom: 14 }} onClick={e => { const r = e.currentTarget.getBoundingClientRect(); setProg(((e.clientX - r.left) / r.width) * 100); }}>
          <div style={{ height: '100%', width: `${prog}%`, background: T.purple, borderRadius: 99, transition: 'width 0.1s' }} />
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
            <button onClick={toggle} style={{ background: T.purple, border: 'none', borderRadius: '50%', width: 38, height: 38, color: '#fff', fontSize: 13, cursor: 'pointer' }}>
              {playing ? '⏸' : '▶'}
            </button>
            <span style={{ color: T.text2, fontSize: 13 }}>{fmt(sec)} / {lesson.duration || '00:00'}</span>
          </div>
          <button onClick={onClose} style={{ background: T.bg3, border: `1px solid ${T.border}`, borderRadius: 8, color: T.text2, padding: '7px 16px', cursor: 'pointer', fontSize: 13 }}>Close</button>
        </div>
      </div>
    </Modal>
  );
}

// ── QUIZ MODAL ───────────────────────────────────────────────────────────────
function QuizModal({ lesson, onClose, onComplete }) {
  const questions = lesson.questions || [];
  const [cur, setCur] = useState(0);
  const [answers, setAnswers] = useState({});
  const [done, setDone] = useState(false);

  if (questions.length === 0) return (
    <Modal onClose={onClose}>
      <div style={{ padding: 32, textAlign: 'center', color: T.text2 }}>No questions added yet.</div>
    </Modal>
  );

  const q = questions[cur];
  const opts = Array.isArray(q.options) ? q.options : JSON.parse(q.options || '[]');
  const score = questions.length > 0
    ? Math.round((Object.entries(answers).filter(([i, a]) => questions[i]?.correct_index === a).length / questions.length) * 100)
    : 0;

  const pick = (i) => {
    if (answers[cur] !== undefined) return;
    setAnswers(a => ({ ...a, [cur]: i }));
    setTimeout(() => {
      if (cur < questions.length - 1) setCur(c => c + 1);
      else setDone(true);
    }, 700);
  };

  if (done) {
    onComplete(score);
    return (
      <Modal onClose={onClose}>
        <div style={{ padding: 40, textAlign: 'center' }}>
          <div style={{ fontSize: 52, marginBottom: 14 }}>{score >= 70 ? '🎉' : '📚'}</div>
          <div style={{ color: T.text, fontSize: 28, fontWeight: 700, marginBottom: 8 }}>{score}%</div>
          <div style={{ color: score >= 70 ? T.green : T.amber, marginBottom: 24 }}>{score >= 70 ? 'Passed!' : 'Keep studying!'}</div>
          <button onClick={onClose} style={{ background: T.purple, border: 'none', borderRadius: 10, padding: '10px 28px', color: '#fff', cursor: 'pointer', fontWeight: 600 }}>Done</button>
        </div>
      </Modal>
    );
  }

  return (
    <Modal onClose={onClose}>
      <div style={{ padding: 32 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
          <span style={{ color: T.purple, fontSize: 13, fontWeight: 600 }}>Question {cur + 1} / {questions.length}</span>
          <button onClick={onClose} style={{ background: 'none', border: 'none', color: T.text3, cursor: 'pointer', fontSize: 18 }}>✕</button>
        </div>
        <Bar val={(cur / questions.length) * 100} />
        <div style={{ color: T.text, fontSize: 17, fontWeight: 600, margin: '22px 0 18px', lineHeight: 1.5 }}>{q.question}</div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {opts.map((opt, i) => {
            const sel = answers[cur] === i;
            const correct = answers[cur] !== undefined && i === q.correct_index;
            const wrong = sel && i !== q.correct_index;
            return (
              <button key={i} onClick={() => pick(i)} style={{ background: correct ? T.green + '22' : wrong ? T.red + '22' : sel ? T.purple + '22' : T.bg2, border: `1.5px solid ${correct ? T.green : wrong ? T.red : sel ? T.purple : T.border}`, borderRadius: 10, padding: '12px 16px', color: correct ? T.green : wrong ? T.red : T.text2, textAlign: 'left', cursor: 'pointer', fontSize: 14, transition: 'all 0.2s' }}>
                <span style={{ marginRight: 10, opacity: 0.5 }}>{String.fromCharCode(65 + i)}.</span>{opt}
              </button>
            );
          })}
        </div>
      </div>
    </Modal>
  );
}

// ── UPLOAD MODAL ─────────────────────────────────────────────────────────────
function UploadModal({ lesson, onClose, onComplete }) {
  const [files, setFiles] = useState([]);
  const [drag, setDrag] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [done, setDone] = useState(false);
  const ref = useRef();

  const addFiles = (fs) => setFiles(p => [...p, ...[...fs].map(f => ({ file: f, name: f.name, size: (f.size / 1024).toFixed(0) + ' KB' }))]);

  const submit = async () => {
    setUploading(true);
    try {
      const form = new FormData();
      files.forEach(f => form.append('files', f.file));
      await api.post(`/upload/${lesson.id}`, form, { headers: { 'Content-Type': 'multipart/form-data' } });
      setDone(true);
      onComplete();
    } catch {
      alert('Upload failed. Please try again.');
    } finally {
      setUploading(false);
    }
  };

  return (
    <Modal onClose={onClose}>
      <div style={{ padding: 32 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 22 }}>
          <div>
            <div style={{ color: T.text, fontSize: 17, fontWeight: 700 }}>{lesson.title}</div>
            {lesson.deadline && <div style={{ color: T.amber, fontSize: 12, marginTop: 3 }}>⏰ Due: {lesson.deadline}</div>}
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', color: T.text3, cursor: 'pointer', fontSize: 18 }}>✕</button>
        </div>
        {done ? (
          <div style={{ textAlign: 'center', padding: '20px 0' }}>
            <div style={{ fontSize: 48, marginBottom: 14 }}>✅</div>
            <div style={{ color: T.green, fontSize: 16, fontWeight: 600 }}>Submitted successfully!</div>
            <button onClick={onClose} style={{ marginTop: 22, background: T.purple, border: 'none', color: '#fff', borderRadius: 10, padding: '10px 24px', cursor: 'pointer', fontWeight: 600 }}>Close</button>
          </div>
        ) : (
          <>
            <div onDragOver={e => { e.preventDefault(); setDrag(true); }} onDragLeave={() => setDrag(false)} onDrop={e => { e.preventDefault(); setDrag(false); addFiles(e.dataTransfer.files); }} onClick={() => ref.current.click()}
              style={{ border: `2px dashed ${drag ? T.purple : T.border2}`, borderRadius: 14, padding: '32px 20px', textAlign: 'center', cursor: 'pointer', background: drag ? T.purple + '0a' : 'transparent', transition: 'all 0.2s' }}>
              <div style={{ fontSize: 28, marginBottom: 10, opacity: 0.6 }}>📎</div>
              <div style={{ color: T.text2, fontSize: 14 }}>Drop files or <span style={{ color: T.purple }}>browse</span></div>
              <div style={{ color: T.text3, fontSize: 11, marginTop: 4 }}>PDF, DOCX, ZIP — max 50MB</div>
              <input ref={ref} type="file" multiple style={{ display: 'none' }} onChange={e => addFiles(e.target.files)} />
            </div>
            {files.map((f, i) => (
              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: T.bg2, borderRadius: 8, padding: '9px 12px', marginTop: 8, border: `1px solid ${T.border}` }}>
                <span style={{ color: T.text2, fontSize: 13 }}>📄 {f.name}</span>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  <span style={{ color: T.text3, fontSize: 11 }}>{f.size}</span>
                  <button onClick={() => setFiles(p => p.filter((_, j) => j !== i))} style={{ background: 'none', border: 'none', color: T.text3, cursor: 'pointer' }}>✕</button>
                </div>
              </div>
            ))}
            {files.length > 0 && (
              <button onClick={submit} disabled={uploading} style={{ width: '100%', marginTop: 14, background: uploading ? T.bg3 : T.purple, border: 'none', color: uploading ? T.text3 : '#fff', borderRadius: 10, padding: 12, cursor: uploading ? 'not-allowed' : 'pointer', fontWeight: 600, fontSize: 14 }}>
                {uploading ? 'Uploading...' : `Submit ${files.length} File${files.length > 1 ? 's' : ''} ↑`}
              </button>
            )}
          </>
        )}
      </div>
    </Modal>
  );
}

function Modal({ children, onClose }) {
  return (
    <div style={{ position: 'fixed', inset: 0, background: '#000000cc', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center', backdropFilter: 'blur(4px)' }} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: T.bg1, borderRadius: 18, width: 'min(680px,95vw)', border: `1px solid ${T.border2}`, overflow: 'hidden', maxHeight: '90vh', overflowY: 'auto' }}>
        {children}
      </div>
    </div>
  );
}

// ── MODULES TAB ──────────────────────────────────────────────────────────────
function ModulesTab() {
  const [modules, setModules] = useState([]);
  const [openMod, setOpenMod] = useState(null);
  const [lessons, setLessons] = useState([]);
  const [activeLesson, setActiveLesson] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/modules').then(r => { setModules(r.data); setLoading(false); });
  }, []);

  const openModule = async (mod) => {
    setOpenMod(mod);
    const r = await api.get(`/modules/${mod.id}/lessons`);
    setLessons(r.data);
  };

  const markDone = async (lessonId, score) => {
    await api.post(`/modules/progress/${lessonId}`, { score });
    setLessons(ls => ls.map(l => l.id === lessonId ? { ...l, done: true, score } : l));
    setModules(ms => ms.map(m => m.id === openMod.id ? { ...m, progress: Math.round(((lessons.filter(l => l.done || l.id === lessonId).length) / lessons.length) * 100) } : m));
  };

  if (loading) return <div style={{ color: T.text3, padding: 20 }}>Loading modules...</div>;

  if (openMod) return (
    <div>
      {activeLesson?.type === 'video' && <VideoModal lesson={activeLesson} onClose={() => setActiveLesson(null)} onComplete={() => markDone(activeLesson.id)} />}
      {activeLesson?.type === 'quiz' && <QuizModal lesson={activeLesson} onClose={() => setActiveLesson(null)} onComplete={(score) => markDone(activeLesson.id, score)} />}
      {activeLesson?.type === 'assignment' && <UploadModal lesson={activeLesson} onClose={() => setActiveLesson(null)} onComplete={() => markDone(activeLesson.id)} />}

      <button onClick={() => setOpenMod(null)} style={{ background: 'none', border: 'none', color: T.purple, cursor: 'pointer', fontSize: 13, marginBottom: 20, padding: 0 }}>← Back to Modules</button>

      <div style={{ background: T.bg1, border: `1px solid ${openMod.color}33`, borderRadius: 16, padding: '22px 24px', marginBottom: 20 }}>
        <div style={{ display: 'flex', gap: 14, alignItems: 'center', marginBottom: 12 }}>
          <div style={{ width: 44, height: 44, borderRadius: 12, background: openMod.color + '22', display: 'flex', alignItems: 'center', justifyContent: 'center', color: openMod.color, fontWeight: 800, fontSize: 20 }}>{openMod.icon}</div>
          <div style={{ flex: 1 }}>
            <div style={{ color: T.text, fontSize: 18, fontWeight: 700, marginBottom: 3 }}>{openMod.title}</div>
            <div style={{ color: T.text2, fontSize: 13 }}>{openMod.description}</div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <div style={{ color: openMod.color, fontSize: 22, fontWeight: 800 }}>{openMod.progress || 0}%</div>
            <div style={{ color: T.text3, fontSize: 11 }}>complete</div>
          </div>
        </div>
        <Bar val={openMod.progress} color={openMod.color} h={6} />
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {lessons.map((lesson, i) => (
          <div key={lesson.id} onClick={() => lesson.type !== 'reading' && setActiveLesson(lesson)}
            style={{ display: 'flex', alignItems: 'center', gap: 14, background: T.bg1, border: `1px solid ${lesson.done ? T.border : T.border2}`, borderRadius: 12, padding: '14px 18px', cursor: lesson.type !== 'reading' ? 'pointer' : 'default', opacity: lesson.done ? 0.75 : 1 }}>
            <div style={{ width: 28, height: 28, borderRadius: '50%', background: lesson.done ? T.green + '22' : T.bg3, border: `1.5px solid ${lesson.done ? T.green : T.border}`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, color: lesson.done ? T.green : T.text3, flexShrink: 0, fontWeight: 700 }}>
              {lesson.done ? '✓' : i + 1}
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ color: T.text, fontSize: 14, fontWeight: 500, marginBottom: 4 }}>{lesson.title}</div>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
                <TypeTag type={lesson.type} />
                {lesson.duration && <span style={{ color: T.text3, fontSize: 11 }}>⏱ {lesson.duration}</span>}
                {lesson.questions?.length > 0 && <span style={{ color: T.text3, fontSize: 11 }}>✦ {lesson.questions.length} questions</span>}
                {lesson.deadline && <span style={{ color: T.amber, fontSize: 11 }}>⏰ Due: {lesson.deadline}</span>}
                {lesson.score != null && <span style={{ color: T.green, fontSize: 11 }}>Score: {lesson.score}%</span>}
              </div>
            </div>
            {!lesson.done && lesson.type !== 'reading' && <span style={{ color: T.text3 }}>›</span>}
          </div>
        ))}
        {lessons.length === 0 && <div style={{ color: T.text3, fontSize: 13, padding: '20px 0' }}>No lessons added yet.</div>}
      </div>
    </div>
  );

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
      {modules.map(m => (
        <div key={m.id} onClick={() => openModule(m)}
          style={{ background: T.bg1, border: `1px solid ${T.border}`, borderRadius: 14, padding: '20px 22px', cursor: 'pointer' }}
          onMouseEnter={e => e.currentTarget.style.borderColor = m.color + '44'}
          onMouseLeave={e => e.currentTarget.style.borderColor = T.border}>
          <div style={{ display: 'flex', gap: 14, alignItems: 'center', marginBottom: 14 }}>
            <div style={{ width: 44, height: 44, borderRadius: 12, background: m.color + '22', display: 'flex', alignItems: 'center', justifyContent: 'center', color: m.color, fontWeight: 800, fontSize: 18, flexShrink: 0 }}>{m.icon}</div>
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 3, flexWrap: 'wrap' }}>
                <div style={{ color: T.text, fontSize: 15, fontWeight: 700 }}>{m.title}</div>
                <Badge label={m.status} color={m.status === 'published' ? T.green : T.amber} />
              </div>
              <div style={{ color: T.text2, fontSize: 13 }}>{m.description}</div>
            </div>
            <div style={{ textAlign: 'right', flexShrink: 0 }}>
              <div style={{ color: m.color, fontSize: 20, fontWeight: 800 }}>{m.progress || 0}%</div>
              <div style={{ color: T.text3, fontSize: 11 }}>{m.lesson_count} lessons</div>
            </div>
          </div>
          <Bar val={m.progress} color={m.color} h={5} />
          <div style={{ display: 'flex', gap: 20, marginTop: 10 }}>
            {m.duration && <span style={{ color: T.text3, fontSize: 12 }}>⏱ {m.duration}</span>}
          </div>
        </div>
      ))}
    </div>
  );
}

// ── CHAT TAB ─────────────────────────────────────────────────────────────────
function ChatTab({ user }) {
  const [msgs, setMsgs] = useState([]);
  const [input, setInput] = useState('');
  const ref = useRef();

  useEffect(() => {
    api.get('/chat').then(r => setMsgs(r.data));
    const iv = setInterval(() => api.get('/chat').then(r => setMsgs(r.data)), 5000);
    return () => clearInterval(iv);
  }, []);

  useEffect(() => ref.current?.scrollIntoView({ behavior: 'smooth' }), [msgs]);

  const send = async () => {
    if (!input.trim()) return;
    const msg = input;
    setInput('');
    const r = await api.post('/chat', { message: msg });
    setMsgs(m => [...m, r.data]);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: 'calc(100vh - 140px)' }}>
      <div style={{ borderBottom: `1px solid ${T.border}`, paddingBottom: 12, marginBottom: 14, display: 'flex', alignItems: 'center', gap: 8 }}>
        <div style={{ width: 8, height: 8, borderRadius: '50%', background: T.green }} />
        <span style={{ color: T.text2, fontSize: 13 }}>Group Chat</span>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 14 }}>
        {msgs.map(m => {
          const self = m.user_id === user.id;
          return (
            <div key={m.id} style={{ display: 'flex', gap: 10, flexDirection: self ? 'row-reverse' : 'row' }}>
              <Av name={m.author_name || '?'} color={m.avatar_color || T.purple} size={32} />
              <div style={{ maxWidth: '72%' }}>
                {!self && <div style={{ color: T.text3, fontSize: 11, marginBottom: 4 }}>{m.author_name}</div>}
                <div style={{ background: self ? T.purple + '33' : T.bg2, border: `1px solid ${self ? T.purple + '44' : T.border}`, color: T.text, borderRadius: self ? '14px 4px 14px 14px' : '4px 14px 14px 14px', padding: '10px 14px', fontSize: 14, lineHeight: 1.55 }}>{m.message}</div>
                <div style={{ color: T.text3, fontSize: 10, marginTop: 4, textAlign: self ? 'right' : 'left' }}>
                  {new Date(m.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          );
        })}
        <div ref={ref} />
      </div>
      <div style={{ display: 'flex', gap: 10, paddingTop: 14, borderTop: `1px solid ${T.border}`, marginTop: 14 }}>
        <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && send()} placeholder="Type a message..." style={{ flex: 1, background: T.bg2, border: `1px solid ${T.border}`, borderRadius: 10, padding: '10px 14px', color: T.text, fontSize: 13, outline: 'none' }} />
        <button onClick={send} style={{ background: T.purple, border: 'none', borderRadius: 10, width: 42, height: 42, color: '#fff', cursor: 'pointer', fontSize: 16 }}>↑</button>
      </div>
    </div>
  );
}

// ── FORUM TAB ────────────────────────────────────────────────────────────────
function ForumTab({ user }) {
  const [posts, setPosts] = useState([]);
  const [filter, setFilter] = useState('');
  const [composing, setComposing] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newBody, setNewBody] = useState('');
  const [newMod, setNewMod] = useState('');
  const [modules, setModules] = useState([]);

  useEffect(() => {
    api.get('/modules').then(r => setModules(r.data));
    loadPosts();
  }, []);

  const loadPosts = async (modId) => {
    const r = await api.get('/forum' + (modId ? `?module_id=${modId}` : ''));
    setPosts(r.data);
  };

  const handleFilter = (v) => { setFilter(v); loadPosts(v || undefined); };

  const submit = async () => {
    if (!newTitle.trim()) return;
    const r = await api.post('/forum', { title: newTitle, body: newBody, module_id: newMod || null });
    setPosts(p => [r.data, ...p]);
    setNewTitle(''); setNewBody(''); setComposing(false);
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16, flexWrap: 'wrap', gap: 8 }}>
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
          <button onClick={() => handleFilter('')} style={{ background: !filter ? T.purple + '22' : 'transparent', color: !filter ? T.purpleL : T.text3, border: `1px solid ${!filter ? T.purple + '44' : T.border}`, borderRadius: 8, padding: '5px 12px', fontSize: 12, cursor: 'pointer' }}>All</button>
          {modules.map(m => (
            <button key={m.id} onClick={() => handleFilter(m.id)} style={{ background: filter === m.id ? m.color + '22' : 'transparent', color: filter === m.id ? m.color : T.text3, border: `1px solid ${filter === m.id ? m.color + '44' : T.border}`, borderRadius: 8, padding: '5px 12px', fontSize: 12, cursor: 'pointer' }}>M{m.order_index}</button>
          ))}
        </div>
        <button onClick={() => setComposing(c => !c)} style={{ background: T.purple, border: 'none', borderRadius: 8, padding: '7px 16px', color: '#fff', cursor: 'pointer', fontSize: 13, fontWeight: 600 }}>+ New Post</button>
      </div>

      {composing && (
        <div style={{ background: T.bg1, border: `1px solid ${T.border2}`, borderRadius: 14, padding: 20, marginBottom: 16 }}>
          <div style={{ display: 'flex', gap: 10, marginBottom: 10, flexWrap: 'wrap' }}>
            <input value={newTitle} onChange={e => setNewTitle(e.target.value)} placeholder="Post title..." style={{ flex: 1, minWidth: 200, background: T.bg2, border: `1px solid ${T.border}`, borderRadius: 8, padding: '9px 12px', color: T.text, fontSize: 14, outline: 'none' }} />
            <select value={newMod} onChange={e => setNewMod(e.target.value)} style={{ background: T.bg2, border: `1px solid ${T.border}`, borderRadius: 8, padding: '9px 12px', color: T.text2, fontSize: 13, outline: 'none' }}>
              <option value="">No module</option>
              {modules.map(m => <option key={m.id} value={m.id}>{m.title}</option>)}
            </select>
          </div>
          <textarea value={newBody} onChange={e => setNewBody(e.target.value)} placeholder="Write your message..." rows={3} style={{ width: '100%', background: T.bg2, border: `1px solid ${T.border}`, borderRadius: 8, padding: '9px 12px', color: T.text2, fontSize: 13, outline: 'none', resize: 'vertical', boxSizing: 'border-box' }} />
          <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 10 }}>
            <button onClick={() => setComposing(false)} style={{ background: 'none', border: `1px solid ${T.border}`, borderRadius: 8, padding: '7px 14px', color: T.text2, cursor: 'pointer' }}>Cancel</button>
            <button onClick={submit} style={{ background: T.purple, border: 'none', borderRadius: 8, padding: '7px 16px', color: '#fff', cursor: 'pointer', fontWeight: 600 }}>Post</button>
          </div>
        </div>
      )}

      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {posts.map(p => (
          <div key={p.id} style={{ background: T.bg1, border: `1px solid ${p.pinned ? T.purple + '44' : T.border}`, borderRadius: 14, padding: '18px 20px' }}>
            {p.pinned && <div style={{ color: T.purple, fontSize: 11, fontWeight: 600, marginBottom: 8 }}>📌 Pinned</div>}
            <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 10 }}>
              <Av name={p.author_name} color={p.avatar_color} size={32} />
              <div>
                <span style={{ color: T.text2, fontSize: 13, fontWeight: 500 }}>{p.author_name}</span>
                <span style={{ color: T.text3, fontSize: 12, marginLeft: 8 }}>{new Date(p.created_at).toLocaleDateString()}</span>
              </div>
            </div>
            <div style={{ color: T.text, fontSize: 15, fontWeight: 600, marginBottom: 6 }}>{p.title}</div>
            <div style={{ color: T.text2, fontSize: 13, lineHeight: 1.6, marginBottom: 10 }}>{p.body}</div>
            <div style={{ color: T.text3, fontSize: 12 }}>💬 {p.reply_count} replies · ♥ {p.likes} likes</div>
          </div>
        ))}
        {posts.length === 0 && <div style={{ color: T.text3, fontSize: 13, padding: '20px 0' }}>No posts yet. Be the first!</div>}
      </div>
    </div>
  );
}

