      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: 12 }}>
        <Stat label="Modules" value={modules.length} color={T.purple} />
        <Stat label="Published" value={modules.filter(m => m.status === 'published').length} color={T.green} />
        <Stat label="Completed" value={modules.filter(m => (m.progress || 0) === 100).length} color={T.amber} />
      </div>

      <div>
        <div style={{ color: T.text, fontSize: 15, fontWeight: 600, marginBottom: 12 }}>Module Overview</div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: 12 }}>
          {modules.map(m => (
            <div key={m.id} style={{ background: T.bg1, border: `1px solid ${T.border}`, borderRadius: 14, padding: '16px 18px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                  <div style={{ width: 32, height: 32, borderRadius: 8, background: m.color + '22', display: 'flex', alignItems: 'center', justifyContent: 'center', color: m.color, fontWeight: 800, fontSize: 14 }}>{m.icon}</div>
                  <div style={{ color: T.text, fontSize: 13, fontWeight: 600 }}>{m.title.split(':')[0]}</div>
                </div>
                <Badge label={`${m.progress || 0}%`} color={m.color} />
              </div>
              <Bar val={m.progress} color={m.color} />
            </div>
          ))}
        </div>
      </div>

      <div>
        <div style={{ color: T.text, fontSize: 15, fontWeight: 600, marginBottom: 12 }}>Announcements</div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {announcements.map(a => (
            <div key={a.id} style={{ display: 'flex', gap: 14, background: T.bg1, border: `1px solid ${T.border}`, borderRadius: 12, padding: '14px 16px', alignItems: 'flex-start' }}>
              <div style={{ fontSize: 18, flexShrink: 0 }}>{a.type === 'info' ? 'ℹ️' : a.type === 'event' ? '📅' : '🆕'}</div>
              <div style={{ flex: 1 }}>
                <div style={{ color: T.text, fontSize: 14, fontWeight: 600, marginBottom: 3 }}>{a.title}</div>
                <div style={{ color: T.text2, fontSize: 13, lineHeight: 1.5 }}>{a.body}</div>
              </div>
              <div style={{ color: T.text3, fontSize: 11, flexShrink: 0 }}>{new Date(a.created_at).toLocaleDateString()}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── MAIN DASHBOARD ───────────────────────────────────────────────────────────
export default function Dashboard() {
  const { user, logout } = useAuth();
  const [tab, setTab] = useState('home');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const isInstructor = user?.role === 'instructor';

  const NAV = [
    { id: 'home', icon: '⊞', label: 'Dashboard' },
    { id: 'modules', icon: '◈', label: 'Modules' },
    { id: 'chat', icon: '◉', label: 'Chat' },
    { id: 'forum', icon: '◆', label: 'Forum' },
    ...(isInstructor ? [{ id: 'students', icon: '◇', label: 'Students' }] : []),
  ];

  const headings = { home: 'Dashboard', modules: 'Modules', chat: 'Group Chat', forum: 'Discussion Forum', students: 'Students' };

  return (
    <>
      <style>{`
        * { box-sizing: border-box; margin: 0; padding: 0; scrollbar-width: thin; scrollbar-color: #2a2a4a transparent; }
        html, body { background: #07070f; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
        input::placeholder, textarea::placeholder { color: #5a5a72; }
        select option { background: #0d0d1c; color: #f0f0f5; }
      `}</style>
      <div style={{ display: 'flex', height: '100vh', background: T.bg }}>
        {/* SIDEBAR */}
        <div style={{ width: sidebarOpen ? 216 : 60, background: T.bg1, borderRight: `1px solid ${T.border}`, display: 'flex', flexDirection: 'column', transition: 'width 0.28s ease', overflow: 'hidden', flexShrink: 0 }}>
          <div style={{ padding: '18px 14px', borderBottom: `1px solid ${T.border}`, display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{ width: 32, height: 32, borderRadius: 10, background: T.purple + '44', border: `1px solid ${T.purple}66`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14, color: T.purple, flexShrink: 0, fontWeight: 800 }}>L</div>
            {sidebarOpen && <span style={{ color: T.text, fontWeight: 800, fontSize: 16, whiteSpace: 'nowrap', letterSpacing: '-0.03em' }}>LearnFlow<span style={{ color: T.purple }}>.</span></span>}
            <button onClick={() => setSidebarOpen(o => !o)} style={{ marginLeft: 'auto', background: 'none', border: 'none', color: T.text3, cursor: 'pointer', flexShrink: 0 }}>
              {sidebarOpen ? '←' : '→'}
            </button>
          </div>
          <nav style={{ padding: '12px 8px', flex: 1, display: 'flex', flexDirection: 'column', gap: 2 }}>
            {NAV.map(n => (
              <button key={n.id} onClick={() => setTab(n.id)} style={{ display: 'flex', alignItems: 'center', gap: 11, padding: '9px 10px', borderRadius: 9, border: 'none', cursor: 'pointer', background: tab === n.id ? T.purple + '22' : 'transparent', color: tab === n.id ? T.purpleL : T.text3, fontSize: 13, fontWeight: tab === n.id ? 600 : 400, transition: 'all 0.13s', whiteSpace: 'nowrap', overflow: 'hidden', textAlign: 'left', width: '100%' }}>
                <span style={{ fontSize: 15, flexShrink: 0 }}>{n.icon}</span>
                {sidebarOpen && n.label}
              </button>
            ))}
          </nav>
          <div style={{ padding: '12px 8px', borderTop: `1px solid ${T.border}` }}>
            {sidebarOpen ? (
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <Av name={user?.name} color={user?.avatar_color || T.purple} size={32} />
                <div style={{ flex: 1, overflow: 'hidden' }}>
                  <div style={{ color: T.text, fontSize: 12, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{user?.name}</div>
                  <div style={{ color: T.text3, fontSize: 11, textTransform: 'capitalize' }}>{user?.role}</div>
                </div>
                <button onClick={logout} title="Logout" style={{ background: 'none', border: 'none', color: T.text3, cursor: 'pointer', fontSize: 14 }}>⏻</button>
              </div>
            ) : (
              <button onClick={logout} style={{ background: 'none', border: 'none', color: T.text3, cursor: 'pointer', fontSize: 16, width: '100%' }}>⏻</button>
            )}
          </div>
        </div>

        {/* MAIN */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          <div style={{ padding: '14px 28px', borderBottom: `1px solid ${T.border}`, background: T.bg, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 }}>
            <div style={{ color: T.text, fontSize: 17, fontWeight: 700 }}>{headings[tab]}</div>
            <Badge label={isInstructor ? '👨‍🏫 Instructor' : '🎓 Student'} color={isInstructor ? T.amber : T.blue} />
          </div>
          <div style={{ flex: 1, overflowY: 'auto', padding: '28px' }}>
            {tab === 'home' && <HomeTab />}
            {tab === 'modules' && <ModulesTab />}
            {tab === 'chat' && <ChatTab user={user} />}
            {tab === 'forum' && <ForumTab user={user} />}
            {tab === 'students' && isInstructor && <StudentsTab />}
          </div>
        </div>
      </div>
    </>
  );
}
